import{_ as t,o as a,c as n,ag as s}from"./chunks/framework.CpPsmr6h.js";const p=JSON.parse('{"title":"HTTP/2 for Beginners","description":"","frontmatter":{},"headers":[],"relativePath":"docs/http2.md","filePath":"docs/http2.md","lastUpdated":1771868171000}'),i={name:"docs/http2.md"};function r(o,e,l,h,c,d){return a(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="http-2-for-beginners" tabindex="-1">HTTP/2 for Beginners <a class="header-anchor" href="#http-2-for-beginners" aria-label="Permalink to &quot;HTTP/2 for Beginners&quot;">​</a></h1><p>HTTP/2 is a newer version of HTTP designed to make web communication faster and more efficient. It keeps the same core concepts as HTTP (requests and responses), but changes how data is sent over the connection.</p><h2 id="what-makes-http-2-different" tabindex="-1">What Makes HTTP/2 Different <a class="header-anchor" href="#what-makes-http-2-different" aria-label="Permalink to &quot;What Makes HTTP/2 Different&quot;">​</a></h2><ul><li>Multiplexing: Multiple requests/responses can share one connection at the same time.</li><li>Header compression: Repeated headers are compressed to reduce bandwidth.</li><li>Binary framing: Data is sent in a compact binary format instead of plain text.</li></ul><h2 id="why-it-matters" tabindex="-1">Why It Matters <a class="header-anchor" href="#why-it-matters" aria-label="Permalink to &quot;Why It Matters&quot;">​</a></h2><ul><li>Pages and APIs can load faster, especially when many assets are requested.</li><li>Less overhead from opening many separate connections.</li><li>Better performance on high-latency networks.</li></ul><h2 id="http-vs-http-2-beginner-view" tabindex="-1">HTTP vs HTTP/2 (Beginner View) <a class="header-anchor" href="#http-vs-http-2-beginner-view" aria-label="Permalink to &quot;HTTP vs HTTP/2 (Beginner View)&quot;">​</a></h2><ul><li>HTTP/1.1: Often uses multiple connections and can be slower with many requests.</li><li>HTTP/2: Uses one connection more efficiently with parallel streams.</li></ul><h2 id="is-it-secure-by-default" tabindex="-1">Is It Secure by Default? <a class="header-anchor" href="#is-it-secure-by-default" aria-label="Permalink to &quot;Is It Secure by Default?&quot;">​</a></h2><p>HTTP/2 itself does not mean encrypted traffic by default, but in practice browsers typically use HTTP/2 over TLS (<code>https</code>).</p><h2 id="when-to-use-http-2" tabindex="-1">When to Use HTTP/2 <a class="header-anchor" href="#when-to-use-http-2" aria-label="Permalink to &quot;When to Use HTTP/2&quot;">​</a></h2><ul><li>You serve web frontends with many assets (JS, CSS, images).</li><li>You want better throughput and reduced latency.</li><li>Your clients and infrastructure support it.</li></ul><h2 id="how-this-works-in-tunnelbox" tabindex="-1">How This Works in TunnelBox <a class="header-anchor" href="#how-this-works-in-tunnelbox" aria-label="Permalink to &quot;How This Works in TunnelBox&quot;">​</a></h2><p><em>TODO: Add TunnelBox-specific HTTP/2 support details, routing behavior, and requirements.</em></p>',14)])])}const f=t(i,[["render",r]]);export{p as __pageData,f as default};
